Here are the public test cases for feature2_buffered_save:
{
  "description": "Rows added to a buffered writer remain pending until saved, then are persisted with their supplied field values and database-backed defaults.",
  "cases": [
    {
      "input": {
        "scenario": "buffered_insert",
        "rows": [
          [
            "Yo",
            15,
            false
          ],
          [
            "Hello",
            25,
            true
          ]
        ]
      },
      "expected_output": "pending_before_save=true\npending_count_before_save=2\ndatabase_count_before_save=0\npending_after_save=false\npending_count_after_save=0\ndatabase_count_after_save=2\ngenerated_id_batches=0\nrecord1.greeting=Yo\nrecord1.age=15\nrecord1.happy=false\nrecord1.color=chartreuse\nrecord1.created_at_present=true\nrecord1.updated_at_present=true\nrecord2.greeting=Hello\nrecord2.age=25\nrecord2.happy=true\nrecord2.color=chartreuse\nrecord2.created_at_present=true\nrecord2.updated_at_present=true\n"
    },
    {
      "input": {
        "scenario": "buffered_insert",
        "rows": [
          {
            "greeting": "Yo",
            "age": 20,
            "happy": false
          }
        ]
      },
      "expected_output": "pending_before_save=true\npending_count_before_save=1\ndatabase_count_before_save=0\npending_after_save=false\npending_count_after_save=0\ndatabase_count_after_save=1\ngenerated_id_batches=0\nrecord1.greeting=Yo\nrecord1.age=20\nrecord1.happy=false\nrecord1.color=chartreuse\nrecord1.created_at_present=true\nrecord1.updated_at_present=true\n"
    },
    {
      "input": {
        "scenario": "buffered_insert",
        "rows": [
          {
            "greeting": "Hello",
            "age": 20,
            "happy": false,
            "color": null
          }
        ]
      },
      "expected_output": "pending_before_save=true\npending_count_before_save=1\ndatabase_count_before_save=0\npending_after_save=false\npending_count_after_save=0\ndatabase_count_after_save=1\ngenerated_id_batches=0\nrecord1.greeting=Hello\nrecord1.age=20\nrecord1.happy=false\nrecord1.color=null\nrecord1.created_at_present=true\nrecord1.updated_at_present=true\n"
    }
  ]
}

