    }
  ]
}

Here are the public test cases for feature4_batch_limit:
{
  "description": "When the queued row count reaches the configured batch limit, adding the next row flushes the current batch automatically and leaves the new row pending until the final save.",
  "cases": [
    {
      "input": {
        "scenario": "batch_limit",
        "batch_limit": 1,
        "rows": [
          [
            "Hello",
            15,
            true
          ],
          [
            "Yo",
            20,
            false
          ]
        ]
      },
      "expected_output": "after_row1_database_count=0\nafter_row1_pending_count=1\nafter_row2_database_count=1\nafter_row2_pending_count=1\nafter_final_save_database_count=2\nrecord1.greeting=Hello\nrecord1.age=15\nrecord1.happy=true\nrecord1.color=chartreuse\nrecord1.created_at_present=true\nrecord1.updated_at_present=true\nrecord2.greeting=Yo\nrecord2.age=20\nrecord2.happy=false\nrecord2.color=chartreuse\nrecord2.created_at_present=true\nrecord2.updated_at_present=true\n"
    }
  ]
}

